mapper.select:
SELECT ID, INSTCD, USERID, NAME, CHANGEDESC, STATUS, CREATED_AT, UPDATED_AT
  FROM TBHISTORY
 WHERE ID = #{id}

SELECT ID, INSTCD, USERID, NAME, CHANGEDESC, STATUS, CREATED_AT, UPDATED_AT
  FROM TBHISTORY
 WHERE 1 = 1

   AND INSTCD = #{instCd}


   AND STATUS = #{status}


   AND NAME LIKE '%' || #{name} || '%'

 /* condition 1: snapshot mismatch check */

   AND NVL(NAME, ' ') <> NVL(CHANGEDESC, ' ')

